const fs = require('fs');
const path = require('path');

const BASE_DIR = path.resolve(__dirname, 'logs'); // Change 'logs' to your intended base directory

function readLogFile(filename) {
    const resolvedPath = path.resolve(BASE_DIR, filename);
    
    if (!resolvedPath.startsWith(BASE_DIR)) {
        throw new Error('Access denied: Attempt to read outside of base directory');
    }

    return new Promise((resolve, reject) => {
        fs.readFile(resolvedPath, 'utf8', (err, data) => {
            if (err) {
                return reject(err);
            }
            resolve(data);
        });
    });
}